		fliptsrv    = fliptserver.New(logger, store)
		metasrv     = metadata.New(cfg, info)
		evalsrv     = evaluation.New(logger, store)
		evalDataSrv = evaluationdata.New(logger, store)
		healthsrv   = health.NewServer()
